#include <bits/stdc++.h>
using namespace std;
int main(){
    int n,k,p=0,z=1;
    cin>>n>>k;
    int a[n]{0};
    for(int i=0;i<n-k;i++){
        for(int j=i;j<i+k;j++){
            a[i]+=j;
        }
    }
    while(z*z<=a[n-1]){
        for(int i=0;i<n;i++){
            if(a[i]==z*z){
                p++;
            }
            if(a[i]>=z*z){
                break;
            }
        }
    }
    cout<<p;
    return 0;
}
